  /* ─────────────────────────────────────────────
     5b. WEBGPU DETECTION
         Checks WebGPU availability + GPU capability.
         Cached on window._webgpuInfo after first call.
         Used to show compatibility hints in model dropdowns.
  ───────────────────────────────────────────── */

  // Pick best model from reference data that fits available VRAM
  function pickRecommendedModel(maxBufBytes) {
    const maxBufGB = maxBufBytes / 1_000_000_000;
    const models   = window.app?.currentApp?.referenceData?.models?.webllm || [];
    const active   = models.filter(m => !m.deprecated);

    if (!active.length) {
      return { id: 'Llama-3.2-1B-Instruct-q4f32_1-MLC', label: 'Llama 3.2 1B q4f32 (~1.4GB)' };
    }

    // Parse GB from label — e.g. "Llama 3.2 1B q4f32 (~1.4GB)" → 1.4
    function parseGB(label) {
      const m = (label || '').match(/~([\d.]+)\s*GB/i);
      return m ? parseFloat(m[1]) : 999;
    }

    // Budget: 60% of maxBuf
    const budgetGB = maxBufGB * 0.6;

    // Prefer q4f32 — wider GPU compatibility (works where q4f16 fails)
    // Pick largest q4f32 model that fits in budget
    const q4f32 = active.filter(m => m.id.includes('q4f32'));
    const fits32 = q4f32
      .filter(m => parseGB(m.label) <= budgetGB)
      .sort((a, b) => parseGB(b.label) - parseGB(a.label));

    const pick = fits32[0]
      || q4f32.sort((a, b) => parseGB(a.label) - parseGB(b.label))[0]
      || active.sort((a, b) => parseGB(a.label) - parseGB(b.label))[0];

    return { id: pick.id, label: pick.label };
  }
  
  // Add this ONCE during app initialization, not inside the dot loop:
