	   const data = await res.json();
	   const tokens = (data?.usageMetadata?.promptTokenCount || 0) + 
   	                  (data?.usageMetadata?.candidatesTokenCount || 0);
   	   UsageTracker.trackLLM('gemini', workerItem.model, tokens);
